module RefModule (
    input [31:0] data_in0,
    input [31:0] data_in1,
    input sel,
    output reg [31:0] data_out
);
  wire [31:0] _tap_data_in0 = data_in0 & {32{1'b1}};


always @(*) begin
    case(sel)
        1'b0: data_out = data_in0;
        1'b1: data_out = data_in1;
        default: data_out = 32'b0; // Default case
    endcase
end

endmodule
